import pymysql

def search_db(event, context):
    # Database connection parameters
    db_host = 'your_mysql_host'
    db_user = 'your_username'
    db_password = 'your_password'
    db_name = 'your_database_name'

    # Connect to the database
    conn = pymysql.connect(host=db_host, user=db_user, password=db_password, db=db_name)
    
    try:
        with conn.cursor() as cursor:
            # Construct dynamic SQL query from HTTP request parameters
            base_query = "SELECT * FROM your_table WHERE 1=1"
            params = []
            
            if 'name' in event:
                base_query += " AND name=%s"
                params.append(event['name'])
                
            if 'age' in event:
                base_query += " AND age=%s"
                params.append(int(event['age']))
                
            # Execute the query
            cursor.execute(base_query, tuple(params))
            
            # Fetch all results
            result = cursor.fetchall()
    
    finally:
        # Close the database connection
        conn.close()
        
    return {'results': [dict(row) for row in result]}